Here's how to write modern MSTest tests for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("Hello, World!", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("Hello, World!", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/data", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_TimeoutViaCancellation_ThrowsBeforeCompletion()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        // Act & Assert — token fires before the slow response completes
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/data", cts.Token));
    }

    // Reusable fake handler to avoid external HTTP calls
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type — MSTest awaits natively |
| **Timeouts** | `[Timeout(ms)]` + `_testContext.CancellationToken` — test auto-cancels if it hangs |
| **Cancellation** | Explicit `CancellationTokenSource` to verify the method respects cancellation |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Sealed class** | Performance + design clarity |
| **Constructor injection** | `TestContext` via constructor for `readonly` safety |

The `FakeHttpMessageHandler` avoids real HTTP calls while letting you control status codes, content, and simulated delays for cancellation/timeout scenarios.
